func localNodeName() string {
	return "Local Node"
}

func progressPercent(value int) string {
	if value < 0 {
		value = 0
	}
	if value > 100 {
		value = 100
	}
	return strconv.Itoa(value) + "%"
}

func commandIcon(label string) string {
	switch label {
	case "Setup":
		return "rocket"
	case "Profiles & Diagnostics":
		return "profiles"
	case "GitOps Review":
		return "gitops"
	case "Access & Cloud":
		return "cloud"
	default:
		return "arrow"
	}
}

func issueIcon(tone string) string {
	switch tone {
	case "green", "blue":
		return "diagnostics"
	case "mauve":
		return "access"
	case "red", "peach":
		return "warning"
	default:
		return "diagnostics"
	}
}

func activityBadge(title string) string {
	lower := strings.ToLower(title)
	switch {
	case strings.Contains(lower, "complete"):
		return "Completed"
	case strings.Contains(lower, "sync"):
		return "Synced"
	case strings.Contains(lower, "access"):
		return "Accessed"
	case strings.Contains(lower, "restart"):
		return "Restarted"
	case strings.Contains(lower, "updated"):
		return "Updated"
	default:
		return "Logged"
	}
}

func firstNonEmpty(values ...string) string {
	for _, value := range values {
		if value != "" {
			return value
		}
	}
	return ""
}

